%[text] # Run samples of the ServiceQueue simulation John McMann
%[text] Collect statistics and plot histograms along the way.
%%
%[text] ## Set up
%[text] We'll measure time in hours
%[text] Arrival rate: 40 per hour
lambda = 40;
%[text] Departure (service) rate: 1 per 2 minutes, so 30 per hour
mu = 30;
%[text] Number of serving stations
s = 2;
%[text] Run 100 samples of the queue.
NumSamples = 100;
%[text] Each sample is run up to a maximum time.
MaxTime = 8;
%[text] Make a log entry every so often
LogInterval = 1/60;
%%
%[text] ## Numbers from theory for M/M/1 queue
%[text] Compute `P(1+n)` = $P\_n$ = probability of finding the system in state $n$ in the long term. Note that this calculation assumes $s=1$.
r = lambda / mu;
rho = r / s;

sum_terms = 0;
for n = 0:(s-1)
    sum_terms = sum_terms + r^n / factorial(n);
end

P0 = 1 / (sum_terms + r^s / (factorial(s) * (1 - rho)));
nMax = 10;
P = zeros([1, nMax+1]);
P(1) = P0;
for n = 1:nMax
    if n <= s
        P(1+n) = (r^n / factorial(n)) * P0;
    else
        P(1+n) = (r^n / (factorial(s) * s^(n-s))) * P0;
    end
end
%%
%[text] ## Run simulation samples
%[text] This is the most time consuming calculation in the script, so let's put it in its own section.  That way, we can run it once, and more easily run the faster calculations multiple times as we add features to this script.
%[text] Reset the random number generator.  This causes MATLAB to use the same sequence of pseudo-random numbers each time you run the script, which means the results come out exactly the same.  This is a good idea for testing purposes.  Under other circumstances, you probably want the random numbers to be truly unpredictable and you wouldn't do this.
rng("default");
%[text] We'll store our queue simulation objects in this list.
QSamples = cell([NumSamples, 1]);
%[text] The statistics come out weird if the log interval is too short, because the log entries are not independent enough.  So the log interval should be long enough for several arrival and departure events happen.
for SampleNum = 1:NumSamples %[output:group:6a12f3f1]
    fprintf("Working on sample %d\n", SampleNum); %[output:317147d0]
    q = ServiceQueue( ...
        ArrivalRate=lambda, ...
        DepartureRate=mu, ...
        NumServers=s, ...
        LogInterval=LogInterval);
    q.schedule_event(Arrival(random(q.InterArrivalDist), Customer(1)));
    run_until(q, MaxTime);
    QSamples{SampleNum} = q;
end %[output:group:6a12f3f1]
%%
%[text] ## Collect measurements of how many customers are in the system
%[text] Count how many customers are in the system at each log entry for each sample run.  There are two ways to do this.  You only have to do one of them.
%[text] ### Option one: Use a for loop.
NumInSystemSamples = cell([NumSamples, 1]);
for SampleNum = 1:NumSamples
    q = QSamples{SampleNum};
    % Pull out samples of the number of customers in the queue system. Each
    % sample run of the queue results in a column of samples of customer
    % counts, because tables like q.Log allow easy extraction of whole
    % columns like this.
    NumInSystemSamples{SampleNum} = q.Log.NumWaiting + q.Log.NumInService;
end

NumWaitingSamples = cell([NumSamples, 1]);
for SampleNum = 1:NumSamples
    q = QSamples{SampleNum};
    % Pull out samples of the number of customers in the queue system. Each
    % sample run of the queue results in a column of samples of customer
    % counts, because tables like q.Log allow easy extraction of whole
    % columns like this.
    NumWaitingSamples{SampleNum} = q.Log.NumWaiting;
end
%[text] ### Option two: Map a function over the cell array of ServiceQueue objects.
%[text] The `@(q) ...` expression is shorthand for a function that takes a `ServiceQueue` as input, names it `q`, and computes the sum of two columns from its log.  The `cellfun` function applies that function to each item in `QSamples`. The option `UniformOutput=false` tells `cellfun` to produce a cell array rather than a numerical array.
NumInSystemSamples = cellfun( ...
    @(q) q.Log.NumWaiting + q.Log.NumInService, ...
    QSamples, ...
    UniformOutput=false);
%[text] ## Join numbers from all sample runs.
%[text] `vertcat` is short for "vertical concatenate", meaning it joins a bunch of arrays vertically, which in this case results in one tall column.
NumInSystem = vertcat(NumInSystemSamples{:});

NumWaitingSystem = vertcat(NumWaitingSamples{:});
%[text] MATLAB-ism: When you pull multiple items from a cell array, the result is a "comma-separated list" rather than some kind of array.  Thus, the above means
%[text] `NumInSystem = vertcat(NumInSystemSamples{1}, NumInSystemSamples{2}, ...)`
%[text] which concatenates all the columns of numbers in NumInSystemSamples into one long column.
%[text] This is roughly equivalent to "splatting" in Python, which looks like `f(*args)`.
%%
%[text] ## Pictures and stats for number of customers in system
%[text] Print out mean number of customers in the system.
meanNumInSystem = mean(NumInSystem);
fprintf("Mean number in system: %f\n", meanNumInSystem); %[output:4a833684]

meanWaitingSystem = mean(NumWaitingSystem);
fprintf("Mean waiting number in system: %f\n", meanWaitingSystem); %[output:701e1398]
%[text] Make a figure with one set of axes.
%%
%[text] ## Collect measurements of how long customers spend in the system
%[text] This is a rather different calculation because instead of looking at log entries for each sample `ServiceQueue`, we'll look at the list of served  customers in each sample `ServiceQueue`.
%[text] ### Option one: Use a for loop.
TimeInSystemSamples = cell([NumSamples, 1]);
for SampleNum = 1:NumSamples
    q = QSamples{SampleNum};
    % The next command has many parts.
    %
    % q.Served is a row vector of all customers served in this particular
    % sample.
    % The ' on q.Served' transposes it to a column.
    %
    % The @(c) ... expression below says given a customer c, compute its
    % departure time minus its arrival time, which is how long c spent in
    % the system.
    %
    % cellfun(@(c) ..., q.Served') means to compute the time each customer
    % in q.Served spent in the system, and build a column vector of the
    % results.
    %
    % The column vector is stored in TimeInSystemSamples{SampleNum}.
    TimeInSystemSamples{SampleNum} = ...
        cellfun(@(c) c.DepartureTime - c.ArrivalTime, q.Served');
end

%[text] ### Option two: Use `cellfun` twice.
%[text] The outer call to `cellfun` means do something to each `ServiceQueue` object in `QSamples`.  The "something" it does is to look at each customer in the `ServiceQueue` object's list `q.Served` and compute the time it spent in the system.
TimeInSystemSamples = cellfun( ...
    @(q) cellfun(@(c) c.DepartureTime - c.ArrivalTime, q.Served'), ...
    QSamples, ...
    UniformOutput=false);

WaitingTimeSamples = cellfun( ...
    @(q) cellfun(@(c) c.BeginServiceTime - c.ArrivalTime, q.Served'), ...
    QSamples, ...
    UniformOutput=false);
%[text] ### Join them all into one big column.
TimeInSystem = vertcat(TimeInSystemSamples{:});

WaitingTime = vertcat(WaitingTimeSamples{:});
%%
%[text] ## Pictures and stats for time customers spend in the system
%[text] Print out mean time spent in the system.
meanTimeInSystem = mean(TimeInSystem);
fprintf("Mean time in system: %f\n", meanTimeInSystem); %[output:1f20cd0f]

meanWaitingTime = mean(WaitingTime);
fprintf("Mean waiting time (Wq): %f\n", meanWaitingTime); %[output:674880b4]
%[text] Make a figure with one set of axes.
%%
%[text] ## Deliverables:
%[text] ### Questions:
%[text] 3\. Find the theoretical values of the following steady-state parameters: 
%%
%[text]   a. $P\_n$: probability of exactly $n$ customers at this bank; give numerical values for $0 \\leq n\\leq 5$
%[text] $\\\[\nP\_n = \\begin{cases}\n\\frac{1}{n!}\\left(\\frac{\\lambda}{\\mu}\\right)^n P\_0 & 1 \\leq n \\leq k \\\\\[10pt\]\n\\frac{1}{k!\\, k^{n-k}}\\left(\\frac{\\lambda}{\\mu}\\right)^n P\_0 & k \\leq n\n\\end{cases}\n\\\]$
%[text]  Where $P\_0$ is
%[text] $\\\[\n\\frac{1}{P\_0} = \\sum\_{n=0}^{k-1} \\frac{1}{n!}\\left(\\frac{\\lambda}{\\mu}\\right)^n \n+ \\frac{1}{k!}\\left(\\frac{\\lambda}{\\mu}\\right)^k \\frac{1}{1-\\rho}\n= 1 + \\frac{4}{3} + \\frac{1}{2}\\left(\\frac{4}{3}\\right)^2 \\frac{1}{1/3} = 5\n\\\]\n\\\[\nP\_0 = \\frac{1}{5} = 0.2\n\\\]\n$
%[text] The probability of 0 customers being in the bank is: $0.2\n$.
%[text] The probability of 1 customers being in the bank is: $P\_1 = \\frac{4/3}{1}(0.2) \\approx 0.2667$.
%[text] The probability of 2 customers being in the bank is: $\\frac{(4/3)^2}{2}(0.2) \\approx 0.1778$.
%[text] The probability of 3 customers being in the bank is: $\\frac{(4/3)^3}{2^2}(0.2) \\approx 0.1185$.
%[text] The probability of 4 customers being in the bank is: $\\frac{(4/3)^4}{2^3}(0.2) \\approx 0.0790$.
%[text] The probability of 5 customers being in the bank is: $\\frac{(4/3)^5}{2^4}(0.2) \\approx 0.0527$.
%%
%[text] b. $L$: expected number of customers in the system, being served plus waiting $\\\[\nL = L\_q + \\frac{\\lambda}{\\mu} = \\frac{16}{15} + \\frac{4}{3} = \\frac{36}{15} = 2.4\n\\\]$. The expected number of customers in the system is 2.4 customers.
%%
%[text] c. $L\_q$: expected number of customers waiting (not being served) 
%[text] $\\\[\nL\_q = \\frac{\\left(\\frac{\\lambda}{\\mu}\\right)^k \\rho}{k!(1-\\rho)^2} P\_0\n= \\frac{(4/3)^2 (2/3)}{2(1/3)^2}(0.2)\n= \\frac{16}{15} \\approx 1.067\n\\\]$.
%[text] The expected number of customers waiting is about 1 customer.
%%
%[text] d. $W$: expected total time in the system, waiting plus service time 
%[text] $\\\[\nW = \\frac{L}{\\lambda} = \\frac{2.4}{40} = 0.06 \\text{ hr} = 3.6 \\text{ min}\n\\\]$
%[text] The expected total time in the system is 3.6 minutes.
%%
%[text] 3\. $W\_q$: expected waiting time in the queue 
%[text] $\\\[\nW\_q = \\frac{L\_q}{\\lambda} = \\frac{16/15}{40} = \\frac{2}{75} \\text{ hr} \\approx 1.6 \\text{ min}\n\\\]$
%[text] The expected waiting time in the queue is about a minute and a half.
%%
%[text] 4\. Set up and run the simulation for this scenario for an 8 hour shift. Generate histograms of the following:
%%
%[text] a. the probability of finding 𝑛 customers in the system; overlay with your theoretical results
fig = figure(); %[output:3f7f962e]
t = tiledlayout(fig,1,1); %[output:3f7f962e]
ax = nexttile(t); %[output:3f7f962e]
hold(ax, "on"); %[output:3f7f962e]
h = histogram(ax, NumInSystem, Normalization="probability", BinMethod="integers"); %[output:3f7f962e]
plot(ax, 0:nMax, P, 'o', MarkerEdgeColor='k', MarkerFaceColor='r'); %[output:3f7f962e]
title(ax, "Number of customers in the system"); %[output:3f7f962e]
xlabel(ax, "Count"); %[output:3f7f962e]
ylabel(ax, "Probability"); %[output:3f7f962e]
legend(ax, "simulation", "theory"); %[output:3f7f962e]
ylim(ax, [0, 0.3]); %[output:3f7f962e]
xlim(ax, [-1, 21]); %[output:3f7f962e]
pause(2);
exportgraphics(fig, "Number in system histogram.pdf"); %[output:3f7f962e]
%%
%[text] b. the total time customers spend in the system
fig = figure(); %[output:17e5a210]
t = tiledlayout(fig,1,1); %[output:17e5a210]
ax = nexttile(t); %[output:17e5a210]
h = histogram(ax, TimeInSystem, Normalization="probability", BinWidth=5/60); %[output:17e5a210]
title(ax, "Time in the system"); %[output:17e5a210]
xlabel(ax, "Time"); %[output:17e5a210]
ylabel(ax, "Probability"); %[output:17e5a210]
ylim(ax, [0, 0.8]); %[output:17e5a210]
xlim(ax, [0, 0.5]); %[output:17e5a210]
pause(2);
exportgraphics(fig, "Time in system histogram.pdf"); %[output:17e5a210]
%%
%[text] 5\. How well do the theoretical results agree with the statistics calculated from the simulation? Express the discrepancy as a percentage of the theoretical value.
%[text] They are quite close! 
%[text] The calculated L value is 
abs((1-meanNumInSystem/2.4)*100) %[output:3f91f176]
%[text] percent more than the theoretical result.
%[text] 
%[text] The calculated Lq value is 
abs((1-meanWaitingSystem/(16/15))*100) %[output:2fd0f9a2]
%[text] percent more than the theoretical result.
%[text] 
%[text] The calculated W value is
abs((1-(meanTimeInSystem / 0.06))*100) %[output:3974ddd4]
%[text] percent more than the theoretical result.
%[text] The calculated Wq value is
abs((1-((meanWaitingTime) / (2/75)))*100) %[output:5190f358]
%[text] percent more than the theoretical result.

